-- ============================================================
-- TESRA - Create table + insert all 876 records
-- Schema: mstr
-- ============================================================

DROP TABLE IF EXISTS mstr.tesra CASCADE;

CREATE TABLE mstr.tesra (
    created_date                    TIMESTAMP,
    last_updated_on                 TIMESTAMP,
    case_status                     VARCHAR(50),
    ep_category_as_advised_by_iesc   VARCHAR(20),
    tesra_ep_categorisation          VARCHAR(50),
    scope_of_application             VARCHAR(200),
    transaction_esra_rating          VARCHAR(50),
    case_id                          INTEGER,
    entity_id                        VARCHAR(50),
    entity_name                      VARCHAR(200),
    deal_id                          VARCHAR(100),
    deal_project_name                VARCHAR(200),
    deal_description                 TEXT,
    deal_outcome                     VARCHAR(100),
    deal_activity_status             VARCHAR(50),
    deal_stage                       VARCHAR(50),
    deal_status                      VARCHAR(50),
    primary_deal_execution_country   VARCHAR(50),
    expected_date_of_completion      TIMESTAMP,
    product_group                    VARCHAR(20),
    product_type                     VARCHAR(100),
    sub_product_type                 VARCHAR(100),
    total_current_year_deal_revenue  VARCHAR(50),
    total_deal_size                  VARCHAR(50),
    scb_hold_amount                  VARCHAR(50),
    sensitive_sector                 VARCHAR(500),
    approver_psid                    VARCHAR(20),
    approver_name                    VARCHAR(100),
    decision_date                    TIMESTAMP,
    assign_to                        VARCHAR(20),
    assign_group                     VARCHAR(50),
    has_client_consent_been_acquired  VARCHAR(20)
);

